css:
/* Override Draakon letterhead */
.print-format,
.page,
.print-format .page {
  padding: 0 !important;
  margin: 0 !important;
}

.print-heading,
.print-heading-template {
  display: none !important;
}

@page {
  size: 100mm 100mm;
  margin: 0;
}

body {
  background: #fff;
  color: #000;
  font-family: Arial, Helvetica, sans-serif;
  margin: 0 !important;
  padding: 0 !important;
}

.label {
  width: 100mm;
  height: 100mm;
  max-height: 100mm;
  position: relative;
  overflow: hidden;
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

.vtext {
  position: absolute;
  transform: rotate(90deg);
  transform-origin: 0 0;
  white-space: nowrap;
  line-height: 1.2;
}

