html:
{# Data Layer #}
{% set dhl_settings = frappe.get_doc("DHL Cargo Settings") %}
{% set sender_customer_no = dhl_settings.customer_number or "" %}
{% set sender_name = doc.company or "" %}

{% set receiver_name = doc.customer_name or "" %}
{% set receiver_addr = "" %}
{% set receiver_city = "" %}
{% set receiver_phone = "" %}
{% if doc.shipping_address_name %}
  {% set ra = frappe.get_doc("Address", doc.shipping_address_name) %}
  {% set receiver_addr = ((ra.address_line1 or "") ~ " " ~ (ra.address_line2 or "")).strip() %}
  {% set receiver_city = ra.city or "" %}
  {% set receiver_phone = ra.phone or "" %}
{% endif %}

{% set reference_id = doc.dhl_reference_id or doc.name %}

{% set content_text = "" %}
{% for item in doc.items %}
  {% if item.item_group and item.item_group not in content_text %}
    {% set content_text = content_text ~ " " ~ item.item_group %}
  {% endif %}
{% endfor %}
{% set content_text = content_text.strip() %}

{% set label_date = frappe.utils.formatdate(doc.modified, "dd/MM/yyyy") %}

{% for bc in doc.dhl_barcodes %}
<div class="label"{% if not loop.last %} style="page-break-after: always;"{% endif %}>
  <div class="vtext title">DHL ECOM SIPARIS BARKODU</div>
  <div class="box-left"></div>
  <div class="vtext alici-label">ALICI</div>
  <div class="vtext alici-name">{{ receiver_name }}</div>
  <div class="vtext alici-addr">{{ receiver_addr }}</div>
  <div class="vtext alici-city">{{ receiver_city }}</div>
  <div class="vtext alici-phone">TEL : {{ receiver_phone }}</div>
  <div class="vtext alici-content-label">Icerik:</div>
  <div class="vtext alici-content-value">{{ content_text }}</div>
  <div class="box-right"></div>
  <div class="vtext gonderen-label">GONDEREN :</div>
  <div class="vtext gonderen-customer">{{ sender_customer_no }}  -  {{ sender_name }}</div>
  <div class="vtext gonderen-placeholder">{PHATAMESAJ1}</div>
  <div class="vtext gonderen-dashes">---------------------------------</div>
  <div class="barcode-wrap">
    <svg id="barcode-{{ loop.index }}"></svg>
  </div>
  <div class="vtext ref-id">{{ reference_id }}</div>
  <div class="vtext bottom-tah">*Tah.Gond.:</div>
  <div class="vtext bottom-count">{{ doc.dhl_barcodes | length }}</div>
  <div class="vtext bottom-kgdesi">KG/DESI : {{ bc.desi|int }}</div>
  <div class="vtext bottom-paket">PAKET</div>
  <div class="vtext bottom-date">{{ label_date }}</div>
  <div class="vtext corner-date">{{ label_date }}</div>
</div>
{% endfor %}

<script src="https://cdn.jsdelivr.net/npm/jsbarcode@3/dist/JsBarcode.all.min.js"></script>
<script>
  {% for bc in doc.dhl_barcodes %}
  JsBarcode("#barcode-{{ loop.index }}", "{{ reference_id }}", {
    format: "CODE128",
    width: 1.5,
    height: 50,
    displayValue: false,
    margin: 0
  });
  {% endfor %}
</script>
